  ('00000007-0000-4000-8000-000000000004', 'Low — 1 day / 5 business days', 'low', 1440, 7200);
insert into public.canned_responses (id, title, body, created_by, created_at) values
  ('00000008-0000-4000-8000-000000000001', 'Acknowledge and set expectations', 'Thanks for getting in touch — I can see the issue and I''m looking into it now. I''ll come back to you with an update within the next few hours, and sooner if I find the cause before then.', '00000001-0000-4000-8000-000000000002', '2025-11-02T09:00:00.000Z'),
  ('00000008-0000-4000-8000-000000000002', 'Request more detail', 'To dig into this I need a little more: which account is affected, roughly when you first noticed it, and what you were doing at the time. A screenshot of the error helps if you have one.', '00000001-0000-4000-8000-000000000002', '2025-11-02T09:00:00.000Z'),
  ('00000008-0000-4000-8000-000000000003', 'Refund issued', 'I''ve issued the refund. It''s back on the original payment method and typically lands within 5–10 business days, depending on your bank. You''ll see it as a credit rather than a reversal of the original charge.', '00000001-0000-4000-8000-000000000002', '2025-11-02T09:00:00.000Z'),
  ('00000008-0000-4000-8000-000000000004', 'Escalating to engineering', 'This one is a genuine bug, so I''ve raised it with our engineering team and attached everything you sent. I''ll keep this ticket open and update you as it moves — you don''t need to chase.', '00000001-0000-4000-8000-000000000002', '2025-11-02T09:00:00.000Z'),
  ('00000008-0000-4000-8000-000000000005', 'Closing after silence', 'I haven''t heard back, so I''m closing this for now. That''s not a problem at all — just reply here if it''s still happening and the ticket reopens with all the context intact.', '00000001-0000-4000-8000-000000000002', '2025-11-02T09:00:00.000Z');
