insert into public.ticket_messages (id, ticket_id, author_id, type, body, created_at) values
  ('0000000a-0000-4000-8000-000000000001', '00000009-0000-4000-8000-000000000001', '00000001-0000-4000-8000-000000000009', 'public_reply', '<p>Good catch. I have raised this internally with the numbers you sent and will keep you posted.</p>', '2026-04-29T18:43:54.716Z'),
  ('0000000a-0000-4000-8000-000000000002', '00000009-0000-4000-8000-000000000001', '00000001-0000-4000-8000-00000000000e', 'public_reply', '<p>Any update on this one? It is starting to affect our own customers.</p>', '2026-04-30T02:36:54.716Z'),
  ('0000000a-0000-4000-8000-000000000003', '00000009-0000-4000-8000-000000000001', '00000001-0000-4000-8000-000000000009', 'public_reply', '<p>Good catch. I have raised this internally with the numbers you sent and will keep you posted.</p>', '2026-04-30T00:43:54.716Z'),
  ('0000000a-0000-4000-8000-000000000004', '00000009-0000-4000-8000-000000000002', '00000001-0000-4000-8000-000000000008', 'public_reply', '<p>I have applied the fix to your account. Could you confirm it looks right from your end?</p>', '2026-07-15T14:00:49.403Z'),
  ('0000000a-0000-4000-8000-000000000005', '00000009-0000-4000-8000-000000000002', '00000001-0000-4000-8000-000000000032', 'public_reply', '<p>Still seeing it, unfortunately. I have attached a fresh screenshot from this morning.</p>', '2026-07-15T18:01:49.403Z'),
  ('0000000a-0000-4000-8000-000000000006', '00000009-0000-4000-8000-000000000003', '00000001-0000-4000-8000-000000000009', 'public_reply', '<p>I have applied the fix to your account. Could you confirm it looks right from your end?</p>', '2026-07-11T01:22:59.825Z'),
  ('0000000a-0000-4000-8000-000000000007', '00000009-0000-4000-8000-000000000004', '00000001-0000-4000-8000-00000000000a', 'public_reply', '<p>Thanks for the detail — that is enough for me to reproduce it. Looking into it now and I will update you shortly.</p>', '2026-02-11T22:38:10.031Z'),
  ('0000000a-0000-4000-8000-000000000008', '00000009-0000-4000-8000-000000000004', '00000001-0000-4000-8000-00000000000a', 'internal_note', '<p>Customer is on the enterprise plan and renews next quarter — worth handling carefully.</p>', '2026-02-11T22:40:10.031Z'),
  ('0000000a-0000-4000-8000-000000000009', '00000009-0000-4000-8000-000000000004', '00000001-0000-4000-8000-000000000031', 'public_reply', '<p>Thanks for the quick response. Let me know if you need anything else from our side.</p>', '2026-02-12T05:01:10.031Z'),
  ('0000000a-0000-4000-8000-00000000000a', '00000009-0000-4000-8000-000000000008', '00000001-0000-4000-8000-000000000009', 'public_reply', '<p>I can see what happened here. It is on our side, not yours, and I am sorting it out.</p>', '2026-06-24T02:53:38.918Z'),
  ('0000000a-0000-4000-8000-00000000000b', '00000009-0000-4000-8000-000000000008', '00000001-0000-4000-8000-000000000021', 'public_reply', '<p>That is confirmed working now — appreciate the turnaround.</p>', '2026-06-24T03:24:38.918Z'),
  ('0000000a-0000-4000-8000-00000000000c', '00000009-0000-4000-8000-000000000009', '00000001-0000-4000-8000-00000000000c', 'public_reply', '<p>I have applied the fix to your account. Could you confirm it looks right from your end?</p>', '2026-03-20T19:50:41.587Z'),
  ('0000000a-0000-4000-8000-00000000000d', '00000009-0000-4000-8000-00000000000a', '00000001-0000-4000-8000-00000000000b', 'public_reply', '<p>Good catch. I have raised this internally with the numbers you sent and will keep you posted.</p>', '2026-07-15T15:34:19.142Z'),
  ('0000000a-0000-4000-8000-00000000000e', '00000009-0000-4000-8000-00000000000a', '00000001-0000-4000-8000-000000000023', 'public_reply', '<p>Thanks for the quick response. Let me know if you need anything else from our side.</p>', '2026-07-15T22:09:19.142Z'),
  ('0000000a-0000-4000-8000-00000000000f', '00000009-0000-4000-8000-00000000000a', '00000001-0000-4000-8000-00000000000b', 'public_reply', '<p>Good catch. I have raised this internally with the numbers you sent and will keep you posted.</p>', '2026-07-15T16:26:19.142Z'),
  ('0000000a-0000-4000-8000-000000000010', '00000009-0000-4000-8000-00000000000a', '00000001-0000-4000-8000-000000000023', 'public_reply', '<p>Thanks for the quick response. Let me know if you need anything else from our side.</p>', '2026-07-16T23:13:19.142Z'),
  ('0000000a-0000-4000-8000-000000000011', '00000009-0000-4000-8000-00000000000b', '00000001-0000-4000-8000-000000000008', 'public_reply', '<p>That is expected behaviour today, though I agree it is surprising. Here is the reasoning, and the workaround in the meantime.</p>', '2026-07-16T08:09:49.128Z'),
  ('0000000a-0000-4000-8000-000000000012', '00000009-0000-4000-8000-00000000000b', '00000001-0000-4000-8000-000000000023', 'public_reply', '<p>That is confirmed working now — appreciate the turnaround.</p>', '2026-07-16T09:18:49.128Z'),
  ('0000000a-0000-4000-8000-000000000013', '00000009-0000-4000-8000-00000000000c', '00000001-0000-4000-8000-00000000000c', 'public_reply', '<p>That is expected behaviour today, though I agree it is surprising. Here is the reasoning, and the workaround in the meantime.</p>', '2026-07-15T10:37:29.271Z'),
  ('0000000a-0000-4000-8000-000000000014', '00000009-0000-4000-8000-00000000000c', '00000001-0000-4000-8000-000000000028', 'public_reply', '<p>Thanks for the quick response. Let me know if you need anything else from our side.</p>', '2026-07-15T12:17:29.271Z'),
  ('0000000a-0000-4000-8000-000000000015', '00000009-0000-4000-8000-00000000000d', '00000001-0000-4000-8000-000000000005', 'public_reply', '<p>That is expected behaviour today, though I agree it is surprising. Here is the reasoning, and the workaround in the meantime.</p>', '2026-06-07T23:18:16.654Z'),
  ('0000000a-0000-4000-8000-000000000016', '00000009-0000-4000-8000-00000000000e', '00000001-0000-4000-8000-000000000003', 'public_reply', '<p>Thanks for the detail — that is enough for me to reproduce it. Looking into it now and I will update you shortly.</p>', '2026-02-13T22:09:56.402Z'),
  ('0000000a-0000-4000-8000-000000000017', '00000009-0000-4000-8000-00000000000e', '00000001-0000-4000-8000-00000000000d', 'public_reply', '<p>That is confirmed working now — appreciate the turnaround.</p>', '2026-02-14T03:43:56.402Z'),
